const leads = $input.first().json.data || [];
const unique = new Map();
const duplicates = [];

for (const lead of leads) {
  const key1 = (lead.website || '').toLowerCase().trim().replace(/^https?:\/\//, '').replace(/\/$/, '');
  const key2 = (lead.email || '').toLowerCase().trim();
  const key3 = (lead.phone || '').replace(/[^0-9]/g, '');

  let matchKey = null;
  if (key1 && unique.has('web:' + key1)) matchKey = 'web:' + key1;
  else if (key2 && unique.has('email:' + key2)) matchKey = 'email:' + key2;
  else if (key3 && key3.length > 7 && unique.has('phone:' + key3)) matchKey = 'phone:' + key3;

  if (matchKey) {
    duplicates.push({...lead, duplicateOf: unique.get(matchKey), matchType: matchKey.split(':')[0]});
  } else {
    if (key1) unique.set('web:' + key1, lead.id);
    if (key2) unique.set('email:' + key2, lead.id);
    if (key3 && key3.length > 7) unique.set('phone:' + key3, lead.id);
  }
}

const cleanLeads = leads.filter(l => !duplicates.find(d => d.id === l.id));
return {cleanLeads, duplicates, totalLeads: leads.length, cleanCount: cleanLeads.length, dupCount: duplicates.length};
